// Filtra solo filas con Email valido y estado correcto
return $input.all().filter(function(item) {
  var email = (item.json.Email || '').trim();
  var estadoEmail = item.json.Estado_Email || '';
  return email.indexOf('@') > -1
    && estadoEmail !== 'Email Enviado'
    && estadoEmail !== 'Follow-up Enviado'
    && estadoEmail !== 'Baja';
});

// Construye email personalizado segun el Estado del cliente
const n      = $json.Nombre || 'Cliente';
const s      = $json.Estado || '';
const emp    = $vars.EMPRESA_NOMBRE  || 'Nuestra Empresa';
const web    = $vars.WEBSITE_URL     || '#';
const wa     = $vars.WHATSAPP_LINK   || '#';
const emailC = $vars.EMAIL_CONTACTO  || '';

// Helper: boton CTA
const btn = (url, txt) =>
  `<a href="${url}" style="display:inline-block;background:#1e40af;color:#fff;padding:12px 24px;text-decoration:none;border-radius:5px;font-weight:bold;margin:10px 0">${txt}</a>`;

// Helper: caja de info
const box = (c) =>
  `<div style="background:#eff6ff;border-left:4px solid #1e40af;padding:12px 16px;margin:15px 0;border-radius:0 5px 5px 0">${c}</div>`;

// Helper: wrapper completo del email
const wrap = (title, body) =>
  `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>` +
  `<body style="font-family:Arial,sans-serif;margin:0;padding:0;background:#f5f5f5">` +
  `<div style="max-width:600px;margin:0 auto;background:#ffffff">` +
  `<div style="background:#1e40af;color:#ffffff;padding:28px 32px">` +
  `<h1 style="margin:0;font-size:22px;font-weight:700">${title}</h1></div>` +
  `<div style="padding:28px 32px;color:#333333;line-height:1.7">${body}</div>` +
  `<div style="background:#f4f4f4;padding:16px 32px;text-align:center;font-size:11px;color:#888888">` +
  `<p style="margin:0">${emailC} &nbsp;|&nbsp; Responde BAJA para cancelar suscripcion</p>` +
  `</div></div></body></html>`;

let subj, html, tpl;

if (s === 'Interesado') {
  tpl  = 'interesado';
  subj = `${n}, aqui esta la informacion que pediste`;
  html = wrap(
    `Gracias por tu interes, ${n}!`,
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Durante nuestra llamada nos comentaste que estas interesado/a en conocer mas. Queremos asegurarnos de darte toda la informacion para que puedas tomar la mejor decision.</p>` +
    box('<strong>Lo que preparamos para vos:</strong><ul style="margin:8px 0;padding-left:20px"><li>Un asesor especializado te contactara en las proximas 24hs</li><li>Propuesta personalizada segun tu perfil</li><li>Reunion informativa sin compromiso ni obligacion</li></ul>') +
    btn(web, 'Ver Mas Informacion') +
    `<p style="margin-top:20px">Cualquier consulta, responde este email o escribinos directamente.</p>` +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );

} else if (s === 'Solicita Devolucion') {
  tpl  = 'callback';
  subj = `${n}, te llamamos pronto`;
  html = wrap(
    `Recibimos tu solicitud de devolucion`,
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Registramos que nos pediste que te devolveramos la llamada. Nuestro equipo te contactara a la brevedad.</p>` +
    box(`Mientras tanto, podes escribirnos por ${btn(wa, 'WhatsApp')} o responder directamente este email con tus consultas.`) +
    `<p>Gracias por tu paciencia.</p>` +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );

} else if (s === 'No Contesta' || s === 'Buzon de Voz') {
  tpl  = 'no_contesta';
  subj = `${n}, intentamos comunicarnos contigo`;
  html = wrap(
    `Quisimos hablar contigo`,
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Intentamos contactarte por telefono pero no pudimos comunicarnos. Queremos contarte sobre una oportunidad que podria interesarte.</p>` +
    `<p>Te dejamos este email para que puedas conocer nuestra propuesta cuando tengas un momento:</p>` +
    btn(web, 'Ver Nuestra Propuesta') +
    `<p>O si prefieres, escribinos directamente por ${btn(wa, 'WhatsApp')}.</p>` +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );

} else if (s === 'No Interesado') {
  tpl  = 'nurture';
  subj = `${n}, quedamos a disposicion cuando lo necesites`;
  html = wrap(
    `Sin presion, entendemos completamente`,
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Entendemos que por ahora no es el momento indicado. Respetamos completamente tu decision.</p>` +
    `<p>Guardamos tu informacion para el futuro. Si en algun momento las circunstancias cambian o surge alguna consulta, estamos a un mensaje de distancia.</p>` +
    btn(wa, 'Contactarnos cuando estes listo/a') +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );

} else if (s === 'Transferido') {
  tpl  = 'transferido';
  subj = `${n}, resumen de tu consulta`;
  html = wrap(
    `Tu consulta fue derivada a un especialista`,
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Durante nuestra llamada te pusimos en contacto con un asesor especializado. Te enviamos este email como confirmacion y para que tengas nuestros datos a mano.</p>` +
    box(`<strong>Contacto directo:</strong><br>Email: <a href="mailto:${emailC}">${emailC}</a><br>WhatsApp: <a href="${wa}">${wa}</a>`) +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );

} else {
  tpl  = 'bienvenida';
  subj = `Hola ${n}, te presentamos ${emp}`;
  html = wrap(
    `Bienvenido/a, ${n}`,
    `<p>Hola <strong>${n}</strong>,</p>` +
    `<p>Somos <strong>${emp}</strong> y queremos contarte lo que podemos hacer por vos. <em>[COMPLETAR CON TU PROPUESTA DE VALOR AQUI]</em></p>` +
    box('<ul style="margin:8px 0;padding-left:20px"><li>Beneficio 1 - Editar esto</li><li>Beneficio 2 - Editar esto</li><li>Beneficio 3 - Editar esto</li></ul>') +
    btn(web, 'Conocer Mas') +
    `<p>Cualquier consulta, respondenos directamente este email.</p>` +
    `<p>Saludos,<br><strong>${emp}</strong></p>`
  );
}

return [{ json: Object.assign({}, $json, {
  subject: subj,
  html: html,
  template_usado: tpl,
  timestamp_email: new Date().toISOString()
}) }];
